CREATE PROCEDURE [dbo].[FAY_ENVIO_CORREO_BASE_DERIVACION_SMS_167]  

AS

BEGIN 
SET NOCOUNT ON;

DECLARE 
    @hoy VARCHAR(8) = CONVERT(VARCHAR(8), GETDATE(), 112),
    @ruta1 NVARCHAR(4000),
    @ruta2 NVARCHAR(4000),
    @correo NVARCHAR(500),
    @asunto NVARCHAR(200),
    @tablaHTML NVARCHAR(MAX),
    @tablaHTML_Ayer NVARCHAR(MAX),
    @bodyFinal NVARCHAR(MAX),
    @CANT VARCHAR(100),
    @FECHA VARCHAR(100),
    @CANT2 VARCHAR(100),
    @FECHA2 VARCHAR(100),
    @ARCHIVO VARCHAR(100),
    @ARCHIVO2 VARCHAR(100),
    @adjuntos NVARCHAR(MAX);


DECLARE 
	@ARCHIVO_CRUCE_PILOTO_CAPTA_MT VARCHAR(100),
	@ruta3 NVARCHAR(4000)

-- =======================================================
-- 1️⃣ Datos base
-- =======================================================
SELECT ROW_NUMBER() OVER(ORDER BY FECHA_HORA DESC) AS ID, *
INTO #T
FROM [Repo_Planificacion].[DBO].[LOG_DIA_ENVIO_SMS_DERIVACION_WSAPP];

SET @CANT = (SELECT CANTIDAD FROM #T WHERE ID = 1);
SET @FECHA = (SELECT FECHA_HORA FROM #T WHERE ID = 1);
SET @ARCHIVO = (SELECT ARCHIVO FROM #T WHERE ID = 1);

IF (RIGHT(@ARCHIVO,6) = '_1.csv')
BEGIN
    SET @ARCHIVO2 = (SELECT ARCHIVO FROM #T WHERE ID = 2);
    SET @CANT2 = (SELECT CANTIDAD FROM #T WHERE ID = 2);
    SET @FECHA2 = (SELECT FECHA_HORA FROM #T WHERE ID = 2);
END
ELSE 
    SET @ARCHIVO2 = '_';

SET @ARCHIVO_CRUCE_PILOTO_CAPTA_MT = @hoy + '_cruce_piloto_capta_mt.csv'


-- =======================================================
-- 2️⃣ Rutas
-- =======================================================
SET @ruta1 = 'K:\Inteligencia_de_Clientes\Proyectos_SSIS\Mensajeria_sms_derivacion_descarga_envio\Procesos\Archivos\' + @ARCHIVO;
SET @ruta2 = 'K:\Inteligencia_de_Clientes\Proyectos_SSIS\Mensajeria_sms_derivacion_descarga_envio\Procesos\Archivos\' + @ARCHIVO2;
SET @ruta3 = 'K:\Inteligencia_de_Clientes\Proyectos_SSIS\Mensajeria_sms_derivacion_descarga_envio\Procesos\Archivos\' + @ARCHIVO_CRUCE_PILOTO_CAPTA_MT;

-- =======================================================
-- 3️⃣ Validar existencia de archivos
-- =======================================================
IF OBJECT_ID('tempdb..#existencia') IS NOT NULL DROP TABLE #existencia;
CREATE TABLE #existencia (FileExists INT, FileIsDir INT, ParentDirExists INT);

INSERT INTO #existencia EXEC master.dbo.xp_fileexist @ruta1;
DECLARE @existe1 BIT = (SELECT CASE WHEN FileExists = 1 THEN 1 ELSE 0 END FROM #existencia);

TRUNCATE TABLE #existencia;
INSERT INTO #existencia EXEC master.dbo.xp_fileexist @ruta2;
DECLARE @existe2 BIT = (SELECT CASE WHEN FileExists = 1 THEN 1 ELSE 0 END FROM #existencia);

TRUNCATE TABLE #existencia;
INSERT INTO #existencia EXEC master.dbo.xp_fileexist @ruta3;
DECLARE @existe3 BIT = (SELECT CASE WHEN FileExists = 1 THEN 1 ELSE 0 END FROM #existencia);

-- =======================================================
-- 4️⃣ Tabla HTML de HOY
-- =======================================================
DECLARE @totalHoy NVARCHAR(20);
SELECT @totalHoy = CAST(SUM(CONVERT(INT, CANTIDAD)) AS NVARCHAR(20))
FROM [Repo_Planificacion].[DBO].[LOG_DIA_ENVIO_SMS_DERIVACION_WSAPP]
WHERE CONVERT(DATE, FECHA_HORA) = CONVERT(DATE, GETDATE());

SET @tablaHTML = 
N'<h3 style="color:#0CACE0;">Reporte de Envíos SMS de hoy</h3>' +
N'<table border="1" cellspacing="0" cellpadding="5" 
       style="border-collapse:collapse; font-family:Arial; font-size:12px; text-align:center;">' +
N'<tr style="background-color:#22C9F1; color:white;">' +
N'<th>ARCHIVO</th><th>FECHA_HORA</th><th>CANTIDAD</th></tr>' +

ISNULL((
    SELECT 
        (
            SELECT 
                CASE 
                    WHEN ARCHIVO IN (@ARCHIVO, @ARCHIVO2)
                        THEN N'<tr style="background-color:#FFF2CC;">'
                    ELSE N'<tr>'
                END +
                N'<td>' + ARCHIVO + N'</td>' +
                N'<td>' + CONVERT(VARCHAR(19), FECHA_HORA, 120) + N'</td>' +
                N'<td align="right">' + CAST(CANTIDAD AS NVARCHAR(20)) + N'</td></tr>'
            FROM [Repo_Planificacion].[DBO].[LOG_DIA_ENVIO_SMS_DERIVACION_WSAPP]
            WHERE CONVERT(DATE, FECHA_HORA) = CONVERT(DATE, GETDATE())
			ORDER BY ARCHIVO
            FOR XML PATH(''), TYPE
        ).value('.', 'NVARCHAR(MAX)')
), '') +

N'<tr style="font-weight:bold; background-color:#f2f2f2;">' +
N'<td colspan="2" align="right">TOTAL:</td>' +
N'<td>' + ISNULL(@totalHoy, '0') + N'</td></tr></table><br>';

-- =======================================================
-- 5️⃣ Tabla HTML de AYER (solo si existe segundo archivo)
-- =======================================================
IF @existe2 = 1
BEGIN
    DECLARE @totalAyer NVARCHAR(20);
    SELECT @totalAyer = CAST(SUM(CONVERT(INT, CANTIDAD)) AS NVARCHAR(20))
    FROM [Repo_Planificacion].[DBO].[LOG_DIA_ENVIO_SMS_DERIVACION_WSAPP]
    WHERE CONVERT(DATE, FECHA_HORA) = DATEADD(DAY, -1, CONVERT(DATE, GETDATE()));

    SET @tablaHTML_Ayer =
    N'<h3 style="color:#0CACE0;">Envío de SMS faltante de ayer</h3>' +
    N'<table border="1" cellspacing="0" cellpadding="5" 
           style="border-collapse:collapse; font-family:Arial; font-size:12px; text-align:center;">' +
    N'<tr style="background-color:#22C9F1; color:white;">' +
    N'<th>ARCHIVO</th><th>FECHA_HORA</th><th>CANTIDAD</th></tr>' +

    ISNULL((
        SELECT 
            (
                SELECT 
                    CASE 
                        WHEN ARCHIVO IN (@ARCHIVO, @ARCHIVO2)
                            THEN N'<tr style="background-color:#FFF2CC;">'
                        ELSE N'<tr>'
                    END +
                    N'<td>' + ARCHIVO + N'</td>' +
                    N'<td>' + CONVERT(VARCHAR(19), FECHA_HORA, 120) + N'</td>' +
                    N'<td align="right">' + CAST(CANTIDAD AS NVARCHAR(20)) + N'</td></tr>'
                FROM [Repo_Planificacion].[DBO].[LOG_DIA_ENVIO_SMS_DERIVACION_WSAPP]
                WHERE CONVERT(DATE, FECHA_HORA) = DATEADD(DAY, -1, CONVERT(DATE, GETDATE()))
				ORDER BY ARCHIVO
                FOR XML PATH(''), TYPE
            ).value('.', 'NVARCHAR(MAX)')
    ), '') +

    N'<tr style="font-weight:bold; background-color:#f2f2f2;">' +
    N'<td colspan="2" align="right">TOTAL:</td>' +
    N'<td>' + ISNULL(@totalAyer, '0') + N'</td></tr></table><br>';
END
ELSE
    SET @tablaHTML_Ayer = N'';

-- =======================================================
-- 6️⃣ Adjuntos
-- =======================================================
IF @existe1 = 1 AND @existe2 = 1
    SET @adjuntos = @ruta1 + ';' + @ruta2;
ELSE IF @existe1 = 1
    SET @adjuntos = @ruta1;
ELSE
    SET @adjuntos = NULL;


--- SE AGREGA EL ARCHIVO DE CRUCE PILOTO CAPTA MT

IF @existe3 = 1 
    SET @adjuntos = @adjuntos + ';' + @ruta3;
ELSE IF @existe1 = 1
    SET @adjuntos = @adjuntos;
ELSE
    SET @adjuntos = NULL;

-- =======================================================
-- 7️⃣ Cuerpo final del correo
-- =======================================================
SET @bodyFinal =
N'<html><body>' +
ISNULL(@tablaHTML_Ayer, N'') +
ISNULL(@tablaHTML, N'') +
N'<p style="font-family:Arial; font-size:12px; color:#000; margin-top:10px;">
El archivo contiene la base de accesos a postventa, sin considerar CDU Baja, Downsell y MigraPre.
</p>
<p style="color:gray;font-size:12px;">Correo enviado automáticamente por Equipo WFM.</p>
</body></html>';

-- =======================================================
-- 8️⃣ Envío de correo
-- =======================================================
IF @adjuntos IS NOT NULL
BEGIN
   -- SET @correo = 'fernando.ayarquispe@telefonica.com';
		SET @correo = 'fernando.ayarquispe@telefonica.com;jose.caballeroo@telefonica.com;gustavo.valverde@telefonica.com'
	--SET @correo = 'fernando.ayarquispe@integratel.com.pe;jose.caballeroo@integratel.com.pe;gustavo.valverde@integratel.com.pe'
    SET @asunto = 'Contact Center Perú - Base Diaria - Envío SMS ' + CONVERT(VARCHAR(10), GETDATE(), 103);

    EXEC msdb.dbo.sp_send_dbmail
        @profile_name = 'info_clte',
        @recipients   = @correo,
        @subject      = @asunto,
        @body         = @bodyFinal,
        @body_format  = 'HTML',
        @file_attachments = @adjuntos;

    PRINT 'Correo enviado con éxito. Archivos: ' + ISNULL(@adjuntos, '');
END
