CREATE FUNCTION [internal].[decrypt_lob_data]
( 
    @key_name nvarchar(255), 
    @KEY varbinary(8000),
    @IV varbinary(8000),
    @lob varbinary(max) 
)
RETURNS varbinary(max)
WITH EXECUTE AS 'AllSchemaOwner'
AS
BEGIN
    DECLARE @decrypted_binary varbinary(MAX)
    SET @decrypted_binary = (SELECT [internal].[decrypt_binarydata](@key_name, @KEY,@IV, @lob))
    RETURN @decrypted_binary
END

CREATE FUNCTION [internal].[encrypt_lob_data]
( 
    @key_name nvarchar(255), 
    @KEY varbinary(8000),
    @IV varbinary(8000),
    @lob varbinary(max) 
)
RETURNS varbinary(max)
AS
BEGIN
    DECLARE @encrypted_binary varbinary(MAX)
    SET @encrypted_binary = (SELECT [internal].[encrypt_binarydata](@key_name, @KEY,@IV, @lob))
    RETURN @encrypted_binary
END
